select 'psql -Upostgres -d$DBNAME -c "\d+ ' || (select nspname from pg_namespace where oid=relnamespace) || '.' || relname || '" > ' || (select nspname from pg_namespace where oid=relnamespace) || '.' || relname || '.log' from pg_class where relispartition = false and relkind in ('r','p') and (select nspname from pg_namespace where oid=relnamespace) not in ('pg_catalog','information_schema') order by 1 asc;
